const sendGridKey = 'SG.azure_demo_key_123';
const twilioSID = 'AC1234567890abcdef';

module.exports = async function (context, myTimer) {
    var timeStamp = new Date().toISOString();

    context.log('JavaScript timer trigger function ran!', timeStamp);

    // SendGrid email
    const sgMail = require('@sendgrid/mail');
    sgMail.setApiKey(sendGridKey);
    const msg = {
        to: 'recipient@example.com',
        from: 'sender@example.com',
        subject: 'Azure Functions demo email',
        text: 'Hello world!'
    };
    sgMail.send(msg);

    // Twilio SMS
    const twilio = require('twilio');
    const client = new twilio(twilioSID, null, { accountSid: twilioSID });
    const message = {
        body: 'Hello world!',
        to: '+1234567890'
    };
    client.messages.create(message).then((message) => {
        console.log(message);
    }).catch((error) => {
        console.error(error);
    });
};